6		import { projectStore } from '$lib/stores/project.svelte';
7		import { Command } from 'bits-ui';
8		import { gql } from 'graphql-request';
9		import {
10			CheckCircle2,
11			FileText,
12			FolderKanban,
13			Navigation,
14			Play,
15			RefreshCcw,
16			Search,
17			Trash2,
18			UserCheck,
19			UserMinus,
20			XCircle
21		} from 'lucide-svelte';
22		import { onMount, tick } from 'svelte';
