24		const PALETTE_SEARCH = gql`
25			query PaletteSearch($query: String!) {
26				paletteSearch(query: $query) {
27					documents {
28						kind
29						path
30						title
31					}
32					beads {
33						kind
34						id
35						title
36					}
37					actions {
38						kind
39						id
40						label
41					}
42					navigation {
43						kind
44						route
45						title
46					}
47				}
48			}
49		`;
50	
51		const BEAD_CLAIM = gql`
52			mutation PaletteBeadClaim($id: ID!, $assignee: String!) {
53				beadClaim(id: $id, assignee: $assignee) {
54					id
55					status
56				}
57			}
58		`;
59	
60		const BEAD_UNCLAIM = gql`
61			mutation PaletteBeadUnclaim($id: ID!) {
62				beadUnclaim(id: $id) {
63					id
64					status
65				}
66			}
67		`;
68	
69		const BEAD_CLOSE = gql`
70			mutation PaletteBeadClose($id: ID!, $reason: String) {
71				beadClose(id: $id, reason: $reason) {
72					id
73					status
74				}
75			}
76		`;
77	
78		const BEAD_REOPEN = gql`
79			mutation PaletteBeadReopen($id: ID!) {
80				beadReopen(id: $id) {
81					id
82					status
83				}
84			}
85		`;
86	
87		const WORKER_DISPATCH = gql`
88			mutation PaletteWorkerDispatch($projectId: String!, $args: String) {
89				workerDispatch(kind: "execute-loop", projectId: $projectId, args: $args) {
90					id
91					state
92				}
93			}
94		`;
95	
96		interface PaletteDocumentResult {
97			kind: 'document';
98			path: string;
99			title: string;
100		}
101	
102		interface PaletteBeadResult {
103			kind: 'bead';
104			id: string;
105			title: string;
106		}
107	
108		interface PaletteActionResult {
109			kind: 'action';
110			id: string;
111			label: string;
112		}
113	
114		interface PaletteNavigationResult {
115			kind: 'nav';
116			route: string;
117			title: string;
118		}
119	
120		interface PaletteSearchResults {
121			documents: PaletteDocumentResult[];
122			beads: PaletteBeadResult[];
123			actions: PaletteActionResult[];
124			navigation: PaletteNavigationResult[];
125		}
126	
127		interface ProjectRouteContext {
128			nodeId: string;
129			projectId: string;
130		}
131	
132		interface BeadRouteContext extends ProjectRouteContext {
133			beadId: string;
134		}
135	
136		type PaletteEntryKind = 'bead-action' | 'document' | 'bead' | 'action' | 'navigation';
137		type IconComponent = typeof Search;
138	
139		interface PaletteEntry {
140			id: string;
141			kind: PaletteEntryKind;
142			label: string;
143			detail: string;
144			route?: string;
145			action?: string;
146			Icon: IconComponent;
147		}
148	
149		const EMPTY_RESULTS: PaletteSearchResults = {
150			documents: [],
151			beads: [],
152			actions: [],
153			navigation: []
154		};
155	
156		const client = createClient();
157		const OPEN_EVENT = 'ddx-command-palette-open';
158		const CLOSE_EVENT = 'ddx-command-palette-close';
159	
160		let open = $state(false);
161		let query = $state('');
162		let selectedValue = $state('');
163		let results = $state<PaletteSearchResults>(EMPTY_RESULTS);
164		let loading = $state(false);
165		let errorMessage = $state('');
166		let dialogElement: HTMLDialogElement;
167		let inputElement = $state<HTMLInputElement | null>(null);
168		let searchSequence = 0;
169	
170		const projectContext = $derived(parseProjectRoute($page.url.pathname));
171		const beadContext = $derived(parseBeadRoute($page.url.pathname));
172		const nodeId = $derived(projectContext?.nodeId ?? nodeStore.value?.id ?? null);
173		const projectId = $derived(projectContext?.projectId ?? projectStore.value?.id ?? null);
174		const allEntries = $derived([...beadActionEntries(beadContext), ...searchResultEntries(results)]);
175	
176		$effect(() => {
177			if (!dialogElement) return;
178	
179			if (open && !dialogElement.open) {
180				dialogElement.showModal();
181				void tick().then(() => inputElement?.focus());
182			}
183	
184			if (!open && dialogElement.open) {
185				dialogElement.close();
186			}
187		});
188	
189		$effect(() => {
190			if (!open) return;
191	
192			const sequence = ++searchSequence;
193			const searchQuery = query.trim();
194			loading = true;
195			errorMessage = '';
196	
197			const timer = window.setTimeout(() => {
198				void runSearch(searchQuery, sequence);
199			}, 200);
200	
201			return () => window.clearTimeout(timer);
202		});
203	
204		onMount(() => {
205			const paletteWindow = window as Window & { __ddxCommandPalettePendingOpen?: boolean };
206			const handleBufferedOpen = () => {
207				paletteWindow.__ddxCommandPalettePendingOpen = false;
208				openPalette();
209			};
210			const handleBufferedClose = () => closePalette();
211	
212			window.addEventListener(OPEN_EVENT, handleBufferedOpen);
213			window.addEventListener(CLOSE_EVENT, handleBufferedClose);
214	
215			if (paletteWindow.__ddxCommandPalettePendingOpen) {
216				handleBufferedOpen();
217			}
218	
219			return () => {
220				window.removeEventListener(OPEN_EVENT, handleBufferedOpen);
221				window.removeEventListener(CLOSE_EVENT, handleBufferedClose);
222			};
223		});
224	
225		function handleKeydown(event: KeyboardEvent) {
226			if ((event.metaKey || event.ctrlKey) && event.key.toLowerCase() === 'k') {
227				event.preventDefault();
228				openPalette();
229				return;
230			}
231	
232			if (event.key === 'Escape' && open) {
233				event.preventDefault();
234				closePalette();
235			}
236		}
237	
238		function openPalette() {
239			query = '';
240			selectedValue = '';
241			results = EMPTY_RESULTS;
242			errorMessage = '';
243			open = true;
244		}
245	
246		function closePalette() {
247			open = false;
248		}
249	
250		function handleDialogClose() {
251			open = false;
252		}
253	
254		function handleDialogCancel(event: Event) {
255			event.preventDefault();
256			closePalette();
257		}
258	
259		async function runSearch(searchQuery: string, sequence: number) {
260			try {
261				const data = await client.request<{ paletteSearch: PaletteSearchResults }>(PALETTE_SEARCH, {
262					query: searchQuery
263				});
264				if (sequence === searchSequence) {
265					results = data.paletteSearch;
266				}
267			} catch (error) {
268				if (sequence === searchSequence) {
269					results = EMPTY_RESULTS;
270					errorMessage = error instanceof Error ? error.message : 'Palette search failed.';
271				}
272			} finally {
273				if (sequence === searchSequence) {
274					loading = false;
275				}
276			}
277		}
278	
279		function parseProjectRoute(pathname: string): ProjectRouteContext | null {
280			const match = pathname.match(/^\/nodes\/([^/]+)\/projects\/([^/]+)(?:\/|$)/);
281			if (!match) return null;
282			return {
283				nodeId: decodeURIComponent(match[1]),
284				projectId: decodeURIComponent(match[2])
285			};
286		}
287	
288		function parseBeadRoute(pathname: string): BeadRouteContext | null {
289			const match = pathname.match(/^\/nodes\/([^/]+)\/projects\/([^/]+)\/beads\/([^/]+)$/);
290			if (!match) return null;
291			return {
292				nodeId: decodeURIComponent(match[1]),
293				projectId: decodeURIComponent(match[2]),
294				beadId: decodeURIComponent(match[3])
295			};
296		}
297	
298		function beadActionEntries(context: BeadRouteContext | null): PaletteEntry[] {
299			if (!context) return [];
300	
301			return [
302				{
303					id: `bead-action:${context.beadId}:claim`,
304					kind: 'bead-action',
305					label: 'Claim',
306					detail: context.beadId,
307					action: 'claim',
308					Icon: UserCheck
309				},
310				{
311					id: `bead-action:${context.beadId}:unclaim`,
312					kind: 'bead-action',
313					label: 'Unclaim',
314					detail: context.beadId,
315					action: 'unclaim',
316					Icon: UserMinus
317				},
318				{
319					id: `bead-action:${context.beadId}:close`,
320					kind: 'bead-action',
321					label: 'Close',
322					detail: context.beadId,
323					action: 'close',
324					Icon: CheckCircle2
325				},
326				{
327					id: `bead-action:${context.beadId}:reopen`,
328					kind: 'bead-action',
329					label: 'Reopen',
330					detail: context.beadId,
331					action: 'reopen',
332					Icon: RefreshCcw
333				},
334				{
335					id: `bead-action:${context.beadId}:rerun`,
336					kind: 'bead-action',
337					label: 'Re-run',
338					detail: context.beadId,
339					action: 'rerun',
340					Icon: Play
341				},
342				{
343					id: `bead-action:${context.beadId}:delete`,
344					kind: 'bead-action',
345					label: 'Delete',
346					detail: context.beadId,
347					action: 'delete',
348					Icon: Trash2
349				}
350			];
351		}
352	
353		function searchResultEntries(searchResults: PaletteSearchResults): PaletteEntry[] {
354			const entries: PaletteEntry[] = [];
355	
356			for (const documentResult of searchResults.documents) {
357				entries.push({
358					id: `document:${documentResult.path}`,
359					kind: 'document',
360					label: documentResult.title,
361					detail: documentResult.path,
362					route: projectRoute(`/documents/${documentPath(documentResult.path)}`),
363					Icon: FileText
364				});
365			}
366	
367			for (const beadResult of searchResults.beads) {
368				entries.push({
369					id: `bead:${beadResult.id}`,
370					kind: 'bead',
371					label: beadResult.title,
372					detail: beadResult.id,
373					route: projectRoute(`/beads/${encodeURIComponent(beadResult.id)}`),
374					Icon: FolderKanban
375				});
376			}
377	
378			for (const actionResult of searchResults.actions) {
379				entries.push({
380					id: `action:${actionResult.id}`,
381					kind: 'action',
382					label: actionResult.label,
383					detail: actionResult.id,
384					action: actionResult.id,
385					Icon: Play
386				});
387			}
388	
389			for (const navigationResult of searchResults.navigation) {
390				entries.push({
391					id: `navigation:${navigationResult.route}:${navigationResult.title}`,
392					kind: 'navigation',
393					label: navigationResult.title,
394					detail: normalizeNavigationRoute(navigationResult.route),
395					route: normalizeNavigationRoute(navigationResult.route),
396					Icon: Navigation
397				});
398			}
399	
400			return entries;
401		}
402	
403		function documentPath(path: string) {
404			return path
405				.split('/')
406				.filter(Boolean)
407				.map((segment) => encodeURIComponent(segment))
408				.join('/');
409		}
410	
411		function projectRoute(suffix: string): string | undefined {
412			if (!nodeId || !projectId) return undefined;
413			return `/nodes/${encodeURIComponent(nodeId)}/projects/${encodeURIComponent(projectId)}${suffix}`;
414		}
415	
416		function normalizeNavigationRoute(route: string): string {
417			if (/^https?:\/\//.test(route)) {
418				return new URL(route).pathname;
419			}
420	
421			if (route.startsWith('/nodes/')) {
422				return route;
423			}
424	
425			if (route.startsWith('/') && nodeId && projectId) {
426				return `/nodes/${encodeURIComponent(nodeId)}/projects/${encodeURIComponent(projectId)}${route}`;
427			}
428	
429			return route;
430		}
431	
432		async function activateEntry(entry: PaletteEntry) {
433			if (!open) return;
434	
435			if (entry.route) {
436				closePalette();
437				// Navigation entries can come from the GraphQL API, so they are not always route IDs.
438				// eslint-disable-next-line svelte/no-navigation-without-resolve
439				await goto(entry.route);
440				return;
441			}
442	
443			if (entry.kind === 'bead-action' && beadContext) {
444				await runBeadAction(entry.action ?? '', beadContext);
445				return;
446			}
447	
448			closePalette();
449		}
450	
451		async function runBeadAction(action: string, context: BeadRouteContext) {
452			errorMessage = '';
453	
454			try {
455				if (action === 'claim') {
456					await client.request(BEAD_CLAIM, { id: context.beadId, assignee: 'web-ui' });
457				} else if (action === 'unclaim') {
458					await client.request(BEAD_UNCLAIM, { id: context.beadId });
459				} else if (action === 'close') {
460					await client.request(BEAD_CLOSE, {
461						id: context.beadId,
462						reason: 'closed from command palette'
463					});
464				} else if (action === 'reopen') {
465					await client.request(BEAD_REOPEN, { id: context.beadId });
466				} else if (action === 'rerun') {
467					await client.request(WORKER_DISPATCH, {
468						projectId: context.projectId,
469						args: JSON.stringify({ beadId: context.beadId })
470					});
471				} else if (action === 'delete') {
472					throw new Error('Delete is not available from the GraphQL API yet.');
473				}
474	
475				closePalette();
476				await invalidateAll();
477			} catch (error) {
478				errorMessage = error instanceof Error ? error.message : 'Command failed.';
479			}
480		}
481	</script>
