529					{:else}
530						<Command.Group>
531							<Command.GroupItems class="py-2">
532								{#each allEntries as entry (entry.id)}
533									<Command.Item
534										role="option"
535										aria-label={entry.action === 'unclaim' ? `Release ${entry.detail}` : undefined}
536										value={entry.id}
537										onSelect={() => void activateEntry(entry)}
538										onclick={() => void activateEntry(entry)}
539										class="flex min-h-11 cursor-pointer items-center gap-3 rounded-none px-3 py-2 text-left text-sm outline-none select-none data-[selected]:bg-bg-surface data-[selected]:text-fg-ink dark:data-[selected]:bg-dark-bg-surface dark:data-[selected]:text-dark-fg-ink"
540									>
541										<entry.Icon class="h-4 w-4 shrink-0 text-fg-muted dark:text-dark-fg-muted" />
542										<span class="min-w-0 flex-1">
543											<span class="block truncate font-medium text-fg-ink dark:text-dark-fg-ink"
544												>{entry.label}</span
545											>
546											<span class="block truncate text-xs text-fg-muted dark:text-dark-fg-muted"
547												>{entry.detail}</span
548											>
549										</span>
550									</Command.Item>
551								{/each}
552							</Command.GroupItems>
553						</Command.Group>
554					{/if}
555				</Command.Viewport>
556			</Command.List>
557		</Command.Root>
